#include<bits/stdc++.h>
using namespace std;
int n,m,k,h;
bool vis[7200010];
int x[7200010],y[7200010],c[7200010],a[7200010];
double dis[7200010];
vector<int> mp[7200010];
vector<pair<int,double>> mp1[7200010];
void dfs(int x)
{
    vis[x]=true;
    if(a[x]==0)
    {
        for(int i=0;i<=k;i++)
        {
            mp1[x+i*n].push_back({i*n+1,0});
        }
    }
    for(int v:mp[x])
    {
        if(!vis[v])
        {
            dfs(v);
        }
    }
}
void dijkstra()
{
    for(int i=1;i<=n*(k+1);i++)
    {
        dis[i]=1e16+20;
        vis[i]=false;
    }
    dis[h]=0;
    priority_queue<pair<double,int>> q;
    q.push({0.0,h});
    while(!q.empty())
    {
        int t=q.top().second;
        q.pop();
        if(vis[t])
        {
            continue;
        }
        vis[t]=true;
        for(auto i:mp1[t])
        {
            int v=i.first;
            double val=i.second;
            if((v-1)%n+1==h)
            {
                continue;
            }
            if(dis[v]>dis[t]+val)
            {
                dis[v]=dis[t]+val;
                q.push({-dis[v],v});
            }
        }
    }
}
double solve(int N,int M,int K,int H,vector<int> X,vector<int> Y,vector<int> C,vector<int> ARR)
{
    n=N,m=M,k=min(K,70),h=H+1;
    for(int i=1;i<=n;i++)
    {
        vis[i]=false;
        a[i]=ARR[i-1];
    }
    vis[h]=true;
    for(int i=1;i<=n*(k+1);i++)
    {
        mp[i].clear();
        mp1[i].clear();
    }
    for(int i=1;i<=m;i++)
    {
        x[i]=X[i-1]+1,y[i]=Y[i-1]+1,c[i]=C[i-1];
        mp[x[i]].push_back(y[i]);
        mp[y[i]].push_back(x[i]);
        // printf("add1(%d,%d)\n",x[i],y[i]);
        // printf("add1(%d,%d)\n",y[i],x[i]);
        double tmp=c[i];
        for(int j=0;j<k;j++)
        {
            // printf("add2((%d,%d),(%d,%d),%lf)\n",x[i],j,y[i],j,tmp);
            // printf("add2((%d,%d),(%d,%d),%lf)\n",y[i],j,x[i],j,tmp);
            // printf("add2((%d,%d),(%d,%d),%lf)\n",x[i],j,y[i],j+1,tmp);
            // printf("add2((%d,%d),(%d,%d),%lf)\n",y[i],j,x[i],j+1,tmp);
            mp1[x[i]+j*n].push_back({y[i]+j*n,tmp});
            mp1[y[i]+j*n].push_back({x[i]+j*n,tmp});
            if(a[y[i]]==2)
            {
                mp1[x[i]+j*n].push_back({y[i]+(j+1)*n,tmp});
            }
            if(a[x[i]]==2)
            {
                mp1[y[i]+j*n].push_back({x[i]+(j+1)*n,tmp});
            }
            tmp/=2.0;
        }
        // printf("add2((%d,%d),(%d,%d),%lf)\n",x[i],k,y[i],k,tmp);
        // printf("add2((%d,%d),(%d,%d),%lf)\n",y[i],k,x[i],k,tmp);
        mp1[x[i]+k*n].push_back({y[i]+k*n,tmp});
        mp1[y[i]+k*n].push_back({x[i]+k*n,tmp});
    }
    dfs(1);
    dijkstra();
    double ans=-1;
    for(int i=0;i<=k;i++)
    {
        if(ans==-1||dis[i*n+1]<ans)
        {
            ans=dis[i*n+1];
        }
    }
    if(ans>1e16)
    {
        ans=-1;
    }
    return ans;
}
