int main()
{
    int t;
    scanf("%d",&t);
    while(t--)
    {
        int n,m,k,h;
        scanf("%d%d%d%d",&n,&m,&k,&h);
        vector<int> arr(n),x(m),y(m),c(m);
        for(int i=0;i<n;i++)
        {
            scanf("%d",&arr[i]);
        }
        for(int i=0;i<m;i++)
        {
            scanf("%d%d%d",&x[i],&y[i],&c[i]);
        }
        printf("%.6lf\n",solve(n,m,k,h,x,y,c,arr));
    }
    return 0;
}
